function solve(n: number, edges: number[][]): number {
    // Build the adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] => edges) {
        adj[u].push([v, w]);
    }

    // Dijkstra's algorithm with a priority queue
    // Each state is (cost, node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at the node has been used
    const pq: [number, number, boolean][] = [[0, 0, false]];
    const dist: Map<string, number> = new Map();
    dist.set("0,false", 0);

    while (pq.length > 0) {
        // Extract the node with the minimum cost
        pq.sort((a, b) => a[0] - b[0]);
        const [cost, node, hasSwitchUsed] = pq.shift()!;
        const key = `${node},${hasSwitchUsed}`;

        // If we've already found a better path to this node, skip
        if (dist.has(key) && dist.get(key) < cost) {
            continue;
        }

        // If we reached the destination node, return the cost
        if (node === n - 1) {
            return cost;
        }

        // Explore neighbors
        for (const [v, w] of adj[node]) {
            // Regular edge
            const newCost = cost + w;
            const newKey = `${v,false}`;
            if (!dist.has(newKey) || dist.get(newKey) > newCost) {
                dist.set(newKey, newCost);
                pq.push([newCost, v, false]);
            }

            // Reverse edge if the switch hasn't been used
            if (!hasSwitchUsed) {
                const reversedCost = cost + 2 * w;
                const reversedKey = `${v,true}`;
                if (!dist.has(reversedKey) || dist.get(reversedKey) > reversedCost) {
                    dist.set(reversedKey, reversedCost);
                    pq.push([reversedCost, v, true]);
                }
            }
        }
    }

    // If we couldn't reach the destination
    return -1;
}

