using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (const auto& [u, v, w] : edges) {
        adj[u].push_back({v, w});
    }

    // Dijkstra's algorithm with a priority queue
    // Each state is (cost, node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at the node has been used
    priority_queue<pair<long long, pair<long long, bool>>, vector<pair<long long, pair<long long, bool>>>, greater<>> pq;
    pq.push({0, {0, false}});

    map<pair<long long, bool>, long long> dist;
    dist[{0, false}] = 0;

    while (!pq.empty()) {
        // Extract the node with the minimum cost
        auto [cost, node_info] = pq.top();
        pq.pop();
        long long node = node_info.first;
        bool hasSwitchUsed = node_info.second;

        // If we've already found a better path to this node, skip
        auto it = dist.find({node, hasSwitchUsed});
        if (it != dist.end() && it->second < cost) {
            continue;
        }

        // If we reached the destination node, return the cost
        if (node == n - 1) {
            return cost;
        }

        // Explore neighbors
        for (const auto& [v, w] : adj[node]) {
            // Regular edge
            long long newCost = cost + w;
            auto newKey = make_pair(v, false);
            if (dist.find(newKey) == dist.end() || dist[newKey] > newCost) {
                dist[newKey] = newCost;
                pq.push({newCost, {v, false}});
            }

            // Reverse edge if the switch hasn't been used
            if (!hasSwitchUsed) {
                long long reversedCost = cost + 2 * w;
                auto reversedKey = make_pair(v, true);
                if (dist.find(reversedKey) == dist.end() || dist[reversedKey] > reversedCost) {
                    dist[reversedKey] = reversedCost;
                    pq.push({reversedCost, {v, true}});
                }
            }
        }
    }

    // If we couldn't reach the destination
    return -1;
}
